#!/usr/bin/env bash
# kfs-1.sh — 品牌新号冷启动 (KFS 阶段 1) SOP walkthrough for 小红书运营.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="小红书运营"
WORKFLOW="品牌新号冷启动 (KFS 阶段 1)"

usage() {
  cat <<EOF
kfs-1.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./kfs-1.sh             # interactive
  ./kfs-1.sh --dry-run
  ./kfs-1.sh --json
  ./kfs-1.sh --explain
  ./kfs-1.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "品牌新号冷启动 (KFS 阶段 1)" 工作流。

一句话: 从 0 到第一篇爆文 (≥ 1k 互动) 的标准动作 — 30 天内站稳基线 + 找到内容方向.

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • 内容是种草, 不是销售 (核心 PASS): 小红书的内容逻辑是「让用户自己想买」, 不是「告诉用户来买」. 硬广直发必死.
  • 数据反馈驱动迭代 (核心 PASS): 小红书运营是**测试驱动的**, 不是经验驱动的 — 每篇笔记都是 A/B 测试.

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**完善账号资料** (Day 1-2): 头像 / 名称 / 简介 / 第一篇置顶笔记. 品牌专业号必须做企业认证 (¥ 600/年)."
  "**对标账号研究** (Day 2-3): 用千瓜找 3-5 个对标账号, 拆其爆款笔记选题 / 封面 / 标题 / 结构. 把它们的选题做成 sheet."
  "**第一周内容 5-7 篇** (Day 3-10): 选题分散, 测试品类边界. 不押单点, 至少覆盖 3-4 个不同选题方向."
  "**24 小时数据看** (Day 10): 互动率 / 收藏率 / 点击率 / 完读率 — 4 个核心指标. 互动率 ≥ 类目均值 1.5x 的算「潜力爆款」."
  "**复盘 + 复刻** (Day 10-15): 数据异常 (爆 / 死) 都立刻复盘. 复刻爆款 (48 小时内 2-3 条同主题). 砍掉死款方向."
  "**第二三周深耕优胜方向** (Day 15-30): 围绕复盘出的优胜方向, 持续输出 5-10 篇. 同步开始小额薯条测试 (¥ 75-300/篇)."
)
declare -a FAILURE_MODES=(
  "资料没完善就发笔记 → 第一篇被限流, 后续起量难"
  "选题太集中 → 测不出账号最适合的内容方向"
  "数据差还硬撑 → 浪费账号权重, 后面爆款都救不回来"
  "矩阵号同手机号管理 → 平台识别为「营销号」, 整组限流"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "kfs-1-walkthrough"
fi
